// ===== NORMALISER LA STRUCTURE DU WEBHOOK =====
const body = $input.first().json.body || $input.first().json;
const event = body.event || '';
const data = body.data || body;

if (event && !event.includes('message')) return [];

let msg = null;
if (Array.isArray(data.messages)) msg = data.messages[0];
else if (data.messages && typeof data.messages === 'object') msg = data.messages;
else if (data.message) msg = data.message;
else msg = data;

if (!msg) return [];

const key = msg.key || {};
const message = msg.message || {};
const remoteJid = key.remoteJid || msg.remoteJid || '';
const fromMe = key.fromMe === true || key.fromMe === 'true';
const pushName = msg.pushName || msg.senderName || '';
const messageTimestamp = msg.messageTimestamp || msg.timestamp || Math.floor(Date.now() / 1000);
const messageId = key.id || msg.id || '';
const participant = key.participant || msg.participant || '';

if (!remoteJid) return [];
if (remoteJid === 'status@broadcast') return [];
if (message.reactionMessage || message.protocolMessage || message.senderKeyDistributionMessage) return [];

let messageBody = msg.messageBody || msg.body || '';
if (!messageBody) messageBody = message.conversation || '';
if (!messageBody) messageBody = message.extendedTextMessage?.text || '';
if (!messageBody) messageBody = message.imageMessage?.caption || '';
if (!messageBody) messageBody = message.videoMessage?.caption || '';

const isGroup = remoteJid.includes('@g.us');

let groupName = '';
if (isGroup) {
  groupName = msg.groupName || msg.groupSubject || '';
  if (!groupName) groupName = data.groupName || data.groupSubject || '';
  if (!groupName) groupName = body.groupName || body.groupSubject || '';
  if (!groupName && msg.groupMetadata) {
    groupName = msg.groupMetadata.subject || msg.groupMetadata.name || '';
  }
  if (!groupName && data.groupMetadata) {
    groupName = data.groupMetadata.subject || data.groupMetadata.name || '';
  }
  if (!groupName && message.extendedTextMessage?.contextInfo?.groupSubject) {
    groupName = message.extendedTextMessage.contextInfo.groupSubject;
  }
  if (!groupName) {
    const search = (obj, depth = 0) => {
      if (!obj || typeof obj !== 'object' || depth > 4) return '';
      for (const k of ['groupName', 'groupSubject', 'subject']) {
        if (obj[k] && typeof obj[k] === 'string') return obj[k];
      }
      for (const k of Object.keys(obj)) {
        if (typeof obj[k] === 'object') {
          const f = search(obj[k], depth + 1);
          if (f) return f;
        }
      }
      return '';
    };
    groupName = search(body);
  }
  if (!groupName) groupName = remoteJid.replace('@g.us', '');
}

let cleanedSenderPn = '';
const toClean = (s) => s ? s.replace(/@s\.whatsapp\.net/g, '').replace(/@lid/g, '').replace(/@g\.us/g, '') : '';

if (isGroup) {
  cleanedSenderPn = toClean(
    key.cleanedParticipantPn || key.participantPn || participant ||
    msg.cleanedParticipantPn || ''
  );
} else {
  cleanedSenderPn = toClean(remoteJid);
}
if (!cleanedSenderPn) cleanedSenderPn = toClean(key.cleanedSenderPn || msg.cleanedSenderPn || '');

const hasAudio = !!message.audioMessage;
const hasImage = !!message.imageMessage;
const hasText = messageBody.trim().length > 0;

if (!hasAudio && !hasText && !hasImage) return [];

return [{
  json: {
    remoteJid, fromMe, pushName, messageTimestamp, messageBody,
    messageId, participant, cleanedSenderPn, isGroup,
    groupName,
    key, message, rawMsg: msg,
    hasAudio, hasImage, hasText
  }
}];

// ===== EXTRACTION ET VALIDATION PUBLICATION GROUPE =====
const normalized = $('Normaliser Webhook').first().json;
const message = normalized.message || {};

const hasImage = normalized.hasImage || !!message.imageMessage;
const hasAudio = normalized.hasAudio || !!message.audioMessage;
const messageBody = (normalized.messageBody || '').trim();
const hasMessageBody = messageBody.length > 0;

if (!hasImage && !hasMessageBody) return [];
if (hasAudio && !hasMessageBody && !hasImage) return [];

let horodatage = '';
try {
  const tsNum = typeof normalized.messageTimestamp === 'string'
    ? parseInt(normalized.messageTimestamp)
    : (normalized.messageTimestamp || 0);
  horodatage = new Date(tsNum * 1000).toLocaleString('fr-FR', { timeZone: 'Africa/Abidjan' });
} catch {
  horodatage = new Date().toLocaleString('fr-FR', { timeZone: 'Africa/Abidjan' });
}

const texte =
  message.imageMessage?.caption ||
  (hasMessageBody ? messageBody : '') ||
  message.conversation ||
  message.extendedTextMessage?.text ||
  '';

const type = hasImage
  ? (texte.length > 0 ? 'image+texte' : 'image')
  : 'texte';

let imageInfo = null;
if (hasImage && message.imageMessage) {
  const im = message.imageMessage;
  imageInfo = {
    url: im.url || '',
    mimetype: im.mimetype || 'image/jpeg',
    mediaKey: im.mediaKey || '',
    directPath: im.directPath || '',
    fileEncSha256: im.fileEncSha256 || '',
    fileSha256: im.fileSha256 || '',
    fileLength: im.fileLength || ''
  };
}

const groupeNom = normalized.isGroup
  ? (normalized.groupName || normalized.remoteJid.replace('@g.us', ''))
  : '';
const groupeJid = normalized.isGroup ? normalized.remoteJid : '';

return [{
  json: {
    Horodatage: horodatage,
    Groupe_Nom: groupeNom,
    Groupe_JID: groupeJid,
    Expediteur: normalized.pushName || '',
    Telephone: normalized.cleanedSenderPn || '',
    Message_ID: normalized.messageId || '',
    Type: type,
    Message: texte,
    has_image: hasImage,
    has_text: texte.length > 0,
    imageInfo: imageInfo,
    Timestamp: normalized.messageTimestamp
  }
}];

const result = $input.first().json;
let publicUrl = result.publicUrl || result.data?.publicUrl || result.url || result.data?.url || '';
const ok = publicUrl.startsWith('http');
return [{ json: { publicUrl: ok ? publicUrl : '', decrypt_ok: ok } }];

const imgResult = $input.first().json;
const extracted = $('Preparer Publication Groupe').first().json;

let lienImage = imgResult?.data?.url
  || imgResult?.data?.display_url
  || $('Verifier Decryptage Image').first().json?.publicUrl
  || '[Upload échoué]';

return [{
