// ===== DÉTECTEUR DE DOUBLONS + GÉNÉRATION REF_BIEN =====

const rawIA = $('IA Extraction Annonce').first().json;
let newAnnonce = {};
try {
  let output = rawIA.output;
  if (typeof output === 'string') {
    const match = output.match(/\{[\s\S]*\}/);
    newAnnonce = match ? JSON.parse(match[0]) : JSON.parse(output);
  } else if (Array.isArray(output)) {
    const text = output[0]?.content?.[0]?.text || output[0]?.text || '{}';
    newAnnonce = typeof text === 'string' ? JSON.parse(text) : text;
  } else if (output && typeof output === 'object') {
    newAnnonce = output;
  }
} catch(e) {
  try {
    const msg = rawIA.message?.content || rawIA.text || '';
    if (typeof msg === 'string') {
      const match = msg.match(/\{[\s\S]*\}/);
      if (match) newAnnonce = JSON.parse(match[0]);
    }
  } catch(e2) {
    return [{ json: { _nouvelle_annonce: true, _parse_error: true, _error: e.message + ' | ' + e2.message } }];
  }
}

if (!newAnnonce.type_de_bien && !newAnnonce.commune && !newAnnonce.prix) {
  return [{ json: { ...newAnnonce, _nouvelle_annonce: true, _parse_error: true, _error: 'Extraction IA vide' } }];
}

const sourceData = $('Extraire Donnees Publication').first().json;

const normalize = (str) => {
  if (!str) return '';
  return String(str).toLowerCase().trim()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/fcfa|f cfa|cfa|francs?/gi, '')
    .replace(/[\s\-.,;:\/\\]+/g, ' ')
    .replace(/[^a-z0-9\s]/g, '')
    .replace(/\s+/g, ' ').trim();
};

const extractNums = (str) => String(str || '').replace(/[^0-9]/g, '');

function generateRefBien(annonce) {
  const typeMap = {
    'appartement': 'APT', 'studio': 'STU', 'chambre': 'CHB', 'maison': 'MAI',
    'villa': 'VIL', 'duplex': 'DPX', 'triplex': 'TPX', 'terrain': 'TER',
    'bureau': 'BUR', 'magasin': 'MAG', 'boutique': 'BTQ', 'entrepot': 'ENT',
    'immeuble': 'IMM', 'local': 'LOC', 'residence': 'RES', 'parking': 'PRK', 'garage': 'GAR'
  };
  const communeMap = {
    'cocody': 'COC', 'yopougon': 'YOP', 'marcory': 'MAR', 'koumassi': 'KOU',
    'treichville': 'TRE', 'plateau': 'PLT', 'adjame': 'ADJ', 'abobo': 'ABO',
    'attecoube': 'ATT', 'port-bouet': 'PBT', 'port bouet': 'PBT',
    'bingerville': 'BIN', 'songon': 'SON', 'anyama': 'ANY', 'bassam': 'BAS',
    'grand-bassam': 'BAS', 'assinie': 'ASS', 'bouake': 'BKE',
    'yamoussoukro': 'YAM', 'san pedro': 'SPD', 'daloa': 'DAL', 'man': 'MAN', 'korhogo': 'KOR'
  };
  const typeNorm = normalize(annonce.type_de_bien || '');
  let typeCode = 'BIE';
  for (const [key, code] of Object.entries(typeMap)) {
    if (typeNorm.includes(key)) { typeCode = code; break; }
  }
  const communeNorm = normalize(annonce.commune || '');
  let communeCode = 'ABJ';
  for (const [key, code] of Object.entries(communeMap)) {
    if (communeNorm.includes(key)) { communeCode = code; break; }
  }
  const now = Date.now();
  const seed = `${typeNorm}${communeNorm}${annonce.quartier || ''}${annonce.prix || ''}${now}`;
  let hash = 0;
  for (let i = 0; i < seed.length; i++) {
    const char = seed.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  const hashHex = Math.abs(hash).toString(16).toUpperCase().slice(-4).padStart(4, '0');
  return `${typeCode}-${communeCode}-${hashHex}`;
}

const n = {
  type: normalize(newAnnonce.type_de_bien || ''),
  commune: normalize(newAnnonce.commune || ''),
  quartier: normalize(newAnnonce.quartier || ''),
  zone: normalize(newAnnonce.zone_geographique || ''),
  prix: extractNums(newAnnonce.prix || ''),
  chambres: extractNums(newAnnonce.chambre || ''),
  meubles: normalize(newAnnonce.meubles || '')
};

let existingItems = [];
try {
  const allItems = $('Charger Annonces Recentes').all();
  existingItems = allItems.map(item => item.json);
  if (existingItems.length === 1 && Array.isArray(existingItems[0])) {
    existingItems = existingItems[0];
  }
} catch(e) {}

let isDuplicate = false;
let bestScore = 0;
let matchedDesc = null;

for (const row of existingItems) {
  if (!row?.type_de_bien) continue;
  const e = {
    type: normalize(row.type_de_bien || ''),
    commune: normalize(row.commune || ''),
    quartier: normalize(row.quartier || ''),
    prix: extractNums(row.prix || ''),
    chambres: extractNums(row.chambre || ''),
    meubles: normalize(row.meubles || '')
  };
  let score = 0;
  const MAX = 11;
  if (e.type && n.type) { if (e.type === n.type) score += 3; else if (e.type.includes(n.type) || n.type.includes(e.type)) score += 2; }
  if (e.commune && n.commune) { if (e.commune === n.commune) score += 2; else if (e.commune.includes(n.commune) || n.commune.includes(e.commune)) score += 1; }
  if (e.quartier && n.quartier) { if (e.quartier === n.quartier) score += 2; else if (e.quartier.includes(n.quartier) || n.quartier.includes(e.quartier)) score += 1; }
  if (e.prix && n.prix) { if (e.prix === n.prix) score += 2; else { const p1 = parseInt(e.prix), p2 = parseInt(n.prix); if (p1 > 0 && p2 > 0) { const diff = Math.abs(p1 - p2) / Math.max(p1, p2); if (diff <= 0.05) score += 1.5; else if (diff <= 0.15) score += 1; } } }
  if (e.chambres && n.chambres) { if (e.chambres === n.chambres) score += 1.5; } else if (!e.chambres && !n.chambres) { score += 0.5; }
  if (e.meubles && n.meubles && e.meubles === n.meubles) score += 0.5;
  const similarity = (score / MAX) * 100;
  if (similarity >= 75 && similarity > bestScore) { isDuplicate = true; bestScore = similarity; matchedDesc = `${row.ref_bien || '?'} | ${row.type_de_bien} - ${row.commune} ${row.quartier} - ${row.prix}`; }
}

const ref_bien = generateRefBien(newAnnonce);
let finalRef = ref_bien;
const existingRefs = existingItems.map(r => r.ref_bien).filter(Boolean);
if (existingRefs.includes(finalRef)) {
  finalRef = `${ref_bien}${Math.random().toString(36).substring(2, 4).toUpperCase()}`;
}

return [{
  json: {
    ...newAnnonce,
    ref_bien: finalRef,
    _is_duplicate: isDuplicate,
    _match_score: Math.round(bestScore),
    _matched_with: matchedDesc,
    _source_groupe_nom: sourceData.groupe || '',
    _source_groupe_jid: sourceData.groupe_jid || '',
    _source_timestamp: sourceData.horodatage || '',
    _source_lien_image: sourceData.lien_image || '',
    _source_message: sourceData.message || '',
    _source_expediteur: sourceData.expediteur || '',
    _source_telephone: sourceData.telephone || '',
    _source_publication_id: sourceData.publication_id || ''
  }
}];

const source = $input.first().json;
const text = source.text || source.messageBody || '';
if (!text || !text.trim()) return [];
return [{ json: { text: text.trim() } }];

const normalized = $('Normaliser Webhook').first().json;

let messageBody = normalized.messageBody || '';
if (!messageBody) messageBody = normalized.message?.conversation || '';
if (!messageBody) messageBody = normalized.message?.extendedTextMessage?.text || '';

if (!messageBody.trim()) {
  return [{ json: { text: '[Message vide reçu]', _debug_no_text: true, _raw_keys: Object.keys(normalized) } }];
}

return [{ json: { text: messageBody.trim() } }];

// Outil de recherche de biens immobiliers dans Supabase
// Le paramètre search_term est fourni par l'agent IA via $fromAI
const searchTerm = $fromAI('search_term', 'le terme de recherche immobilier', 'string');

if (!searchTerm || !searchTerm.trim()) {
  return JSON.stringify({ resultats: [], message: 'Aucun terme de recherche fourni' });
}

const term = searchTerm.trim();
const encodedTerm = encodeURIComponent('*' + term + '*');

const baseUrl = 'https://udyfhzyvalansmhkynnc.supabase.co/rest/v1/locaux';
const select = 'ref_bien,type_de_bien,type_offre,commune,quartier,prix,caracteristiques,meubles,chambre,zone_geographique,lien_image';
const filter = `or=(type_de_bien.ilike.${encodedTerm},commune.ilike.${encodedTerm},quartier.ilike.${encodedTerm},ref_bien.ilike.${encodedTerm},caracteristiques.ilike.${encodedTerm},zone_geographique.ilike.${encodedTerm})`;
const url = `${baseUrl}?disponible=eq.Oui&${filter}&select=${select}&limit=5`;

const apiKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InVkeWZoenl2YWxhbnNtaGt5bm5jIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTE5NjM1NywiZXhwIjoyMDg2NzcyMzU3fQ.XToUDvcD-crlO0bA8HuJ5g1GjhqTl790fHG6H8bujAk';

try {
  const response = await fetch(url, {
    method: 'GET',
    headers: {
      'apikey': apiKey,
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    }
  });

  if (!response.ok) {
    return JSON.stringify({
      resultats: [],
      message: `Erreur de recherche (${response.status}). Aucun bien trouvé pour "${term}".`
    });
  }

  const data = await response.json();

  if (!data || data.length === 0) {
    return JSON.stringify({
      resultats: [],
      message: `Aucun bien disponible trouvé pour "${term}". Essayez un autre terme.`
    });
  }

  const resultats = data.map(bien => ({
    ref_bien: bien.ref_bien || '',
    type_de_bien: bien.type_de_bien || '',
    type_offre: bien.type_offre || '',
    commune: bien.commune || '',
    quartier: bien.quartier || '',
    prix: bien.prix || '',
    caracteristiques: bien.caracteristiques || '',
    meubles: bien.meubles || '',
    chambre: bien.chambre || '',
    zone_geographique: bien.zone_geographique || '',
    lien_image: bien.lien_image || ''
  }));

  return JSON.stringify({
    resultats: resultats,
    nombre: resultats.length,
    message: `${resultats.length} bien(s) trouvé(s) pour "${term}".`
  });

} catch (error) {
  return JSON.stringify({
    resultats: [],
    message: `Recherche impossible pour le moment. Aucun bien trouvé pour "${term}".`
  });
}

