let agentReply = '';
try {
  agentReply = $('Agent Conversationnel').first().json.output || '';
} catch(e) {
  agentReply = 'Bonjour ! Je suis disponible pour vous aider dans votre recherche immobilière. Que recherchez-vous ?';
}

let analysis = {};
try {
  const raw = $('Extracteur Metadonnees').first().json;
  let output = raw.output;
  if (typeof output === 'string') {
    const match = output.match(/\{[\s\S]*\}/);
    analysis = match ? JSON.parse(match[0]) : JSON.parse(output);
  } else if (Array.isArray(output)) {
    const text = output[0]?.content?.[0]?.text || output[0]?.text || '{}';
    analysis = typeof text === 'string' ? JSON.parse(text) : text;
  } else if (output && typeof output === 'object') {
    analysis = output;
  }
} catch(e) {
  analysis = {};
}

const toBool = (v) => v === true || v === 'true';
const toStr = (v) => String(v || '').trim();

return [{
  json: {
    reply: agentReply,
    interesse: toBool(analysis.interesse),
    transfert_urgent: toBool(analysis.transfert_urgent),
    montrer_media: toBool(analysis.montrer_media),
    visite_programme: toBool(analysis.visite_programme),
    nom: toStr(analysis.nom),
    date_rv: toStr(analysis.date_rv),
    local_interesse: toStr(analysis.local_interesse),
    ref_bien: toStr(analysis.ref_bien)
  }
}];

// Vérifier si la visite existe déjà de manière robuste
const items = $input.all();
let visites = [];

for (const item of items) {
  const data = item.json;
  if (Array.isArray(data)) {
    visites = visites.concat(data);
  } else if (data && typeof data === 'object' && data.id) {
    visites.push(data);
  }
}

const isNew = visites.length === 0;

return [{ json: { is_new_visite: isNew, existing_count: visites.length } }];

const localInteresse = $('Parser Analyse').first().json.local_interesse || '';
const refBien = $('Parser Analyse').first().json.ref_bien || '';

if (!localInteresse.trim() && !refBien.trim()) {
