const rawIA = $('IA Extraction Annonce').first().json;
let newAnnonce = {};
try {
  let output = rawIA.output;
  if (typeof output === 'string') {
    const match = output.match(/\{[\s\S]*\}/);
    newAnnonce = match ? JSON.parse(match[0]) : JSON.parse(output);
  } else if (Array.isArray(output)) {
    const text = output[0]?.content?.[0]?.text || output[0]?.text || '{}';
    newAnnonce = typeof text === 'string' ? JSON.parse(text) : text;
  } else if (output && typeof output === 'object') {
    newAnnonce = output;
  }
} catch(e) {
  try {
    const msg = rawIA.message?.content || rawIA.text || '';
    if (typeof msg === 'string') {
      const match = msg.match(/\{[\s\S]*\}/);
      if (match) newAnnonce = JSON.parse(match[0]);
    }
  } catch(e2) {
    return [{ json: { _nouvelle_annonce: true, _parse_error: true, _error: e.message + ' | ' + e2.message } }];
  }
}

if (!newAnnonce.type_de_bien && !newAnnonce.commune && !newAnnonce.prix) {
  return [{ json: { ...newAnnonce, _nouvelle_annonce: true, _parse_error: true, _error: 'Extraction IA vide' } }];
}

const sourceData = $('Extraire Donnees Publication').first().json;

const normalize = (str) => {
  if (!str) return '';
  return String(str).toLowerCase().trim()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/fcfa|f cfa|cfa|francs?/gi, '')
    .replace(/[\s\-.,;:\/\\]+/g, ' ')
    .replace(/[^a-z0-9\s]/g, '')
    .replace(/\s+/g, ' ').trim();
};

const extractNums = (str) => String(str || '').replace(/[^0-9]/g, '');

function generateRefBien(annonce) {
  const typeMap = {
    'appartement': 'APT', 'studio': 'STU', 'chambre': 'CHB', 'maison': 'MAI',
    'villa': 'VIL', 'duplex': 'DPX', 'triplex': 'TPX', 'terrain': 'TER',
    'bureau': 'BUR', 'magasin': 'MAG', 'boutique': 'BTQ', 'entrepot': 'ENT',
    'immeuble': 'IMM', 'local': 'LOC', 'residence': 'RES', 'parking': 'PRK', 'garage': 'GAR'
  };
  const communeMap = {
    'cocody': 'COC', 'yopougon': 'YOP', 'marcory': 'MAR', 'koumassi': 'KOU',
    'treichville': 'TRE', 'plateau': 'PLT', 'adjame': 'ADJ', 'abobo': 'ABO',
    'attecoube': 'ATT', 'port-bouet': 'PBT', 'port bouet': 'PBT',
    'bingerville': 'BIN', 'songon': 'SON', 'anyama': 'ANY', 'bassam': 'BAS',
    'grand-bassam': 'BAS', 'assinie': 'ASS', 'bouake': 'BKE',
    'yamoussoukro': 'YAM', 'san pedro': 'SPD', 'daloa': 'DAL', 'man': 'MAN', 'korhogo': 'KOR'
  };
  const typeNorm = normalize(annonce.type_de_bien || '');
  let typeCode = 'BIE';
  for (const [key, code] of Object.entries(typeMap)) {
    if (typeNorm.includes(key)) { typeCode = code; break; }
  }
  const communeNorm = normalize(annonce.commune || '');
  let communeCode = 'ABJ';
  for (const [key, code] of Object.entries(communeMap)) {
    if (communeNorm.includes(key)) { communeCode = code; break; }
  }
  const now = Date.now();
  const seed = `${typeNorm}${communeNorm}${annonce.quartier || ''}${annonce.prix || ''}${now}`;
  let hash = 0;
  for (let i = 0; i < seed.length; i++) {
    const char = seed.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  const hashHex = Math.abs(hash).toString(16).toUpperCase().slice(-4).padStart(4, '0');
  return `${typeCode}-${communeCode}-${hashHex}`;
}

const n = {
