  if (e.type && n.type) { if (e.type === n.type) score += 3; else if (e.type.includes(n.type) || n.type.includes(e.type)) score += 2; }
  if (e.commune && n.commune) { if (e.commune === n.commune) score += 2; else if (e.commune.includes(n.commune) || n.commune.includes(e.commune)) score += 1; }
  if (e.quartier && n.quartier) { if (e.quartier === n.quartier) score += 2; else if (e.quartier.includes(n.quartier) || n.quartier.includes(e.quartier)) score += 1; }
  if (e.prix && n.prix) { if (e.prix === n.prix) score += 2; else { const p1 = parseInt(e.prix), p2 = parseInt(n.prix); if (p1 > 0 && p2 > 0) { const diff = Math.abs(p1 - p2) / Math.max(p1, p2); if (diff <= 0.05) score += 1.5; else if (diff <= 0.15) score += 1; } } }
  if (e.chambres && n.chambres) { if (e.chambres === n.chambres) score += 1.5; } else if (!e.chambres && !n.chambres) { score += 0.5; }
  if (e.meubles && n.meubles && e.meubles === n.meubles) score += 0.5;
  const similarity = (score / MAX) * 100;
  if (similarity >= 75 && similarity > bestScore) { isDuplicate = true; bestScore = similarity; matchedDesc = `${row.ref_bien || '?'} | ${row.type_de_bien} - ${row.commune} ${row.quartier} - ${row.prix}`; }
}

const ref_bien = generateRefBien(newAnnonce);
let finalRef = ref_bien;
const existingRefs = existingItems.map(r => r.ref_bien).filter(Boolean);
if (existingRefs.includes(finalRef)) {
  finalRef = `${ref_bien}${Math.random().toString(36).substring(2, 4).toUpperCase()}`;
}

return [{
