  }));

  return JSON.stringify({
    resultats: resultats,
    nombre: resultats.length,
    message: `${resultats.length} bien(s) trouvé(s) pour "${term}".`
  });

} catch (error) {
  return JSON.stringify({
    resultats: [],
    message: `Recherche impossible pour le moment. Aucun bien trouvé pour "${term}".`
  });
}

